const projeto = $('Limit — 1 projeto').item.json;
const itens = $input.all().map(i => i.json);
const sociais = itens.filter(c => c.agente === 'social_media');

const tema = (projeto.plano && projeto.plano.resultado && projeto.plano.resultado.tema) || projeto.brief || 'Sem tema';
const dataPub = (projeto.plano && projeto.plano.resultado && projeto.plano.resultado.data_sugerida_publicacao) || '';
const cta = (projeto.plano && projeto.plano.resultado && projeto.plano.resultado.cta_da_campanha) || '';

const lines = [];
lines.push('# OutVibe — Pronto para publicar (Instagram)');
lines.push('');
lines.push(`- **Projeto:** \`${projeto.id}\``);
lines.push(`- **Tema:** ${tema}`);
lines.push(`- **Brief / ficheiro:** ${projeto.brief || '—'}`);
lines.push(`- **CTA campanha:** ${cta}`);
lines.push(`- **Data sugerida:** ${dataPub || '—'}`);
lines.push(`- **Gerado em:** ${new Date().toISOString()}`);
lines.push('');
lines.push('> Publicação **manual**. Copia cada bloco para o Instagram.');
lines.push('');
lines.push('## Calendário rápido');
lines.push('');

sociais.forEach((row, idx) => {
  const c = row.conteudo || {};
  const formato = c.formato || row.tipo || ('peca-' + (idx + 1));
  const hora = c.melhor_horario_sugerido || '—';
  lines.push(`${idx + 1}. **${formato}** — ${dataPub || 'data TBD'} ${hora} · foto: ${c.foto || projeto.brief || '—'}`);
});

lines.push('');
lines.push('---');
lines.push('');

sociais.forEach((row, idx) => {
  const c = row.conteudo || {};
  const formato = c.formato || row.tipo || ('peca-' + (idx + 1));
  const texto = c.texto_final || JSON.stringify(c, null, 2);
  const tags = Array.isArray(c.hashtags) ? c.hashtags.map(h => h.startsWith('#') ? h : '#' + h).join(' ') : '';
  const notas = c.notas_publicacao_manual || '—';
  const hora = c.melhor_horario_sugerido || '—';

  lines.push(`## ${idx + 1}. Instagram — ${formato}`);
  lines.push('');
  lines.push(`- Horário sugerido: **${hora}**`);
  lines.push(`- Foto: \`${c.foto || projeto.brief || '—'}\``);
  lines.push('');
  lines.push('### Legenda (copiar)');
  lines.push('');
  lines.push('```');
  lines.push(texto);
  if (tags) {
    lines.push('');
    lines.push(tags);
  }
  lines.push('```');
  lines.push('');
  lines.push('### Notas para publicar à mão');
  lines.push('');
  lines.push(notas);
  lines.push('');
  lines.push('---');
  lines.push('');
});

const markdown = lines.join('\n');
const safeTema = String(tema).replace(/[^\w\-]+/g, '_').slice(0, 40);
const filename = `IG_${safeTema}_${String(projeto.id).slice(0, 8)}.md`;

const binary = await this.helpers.prepareBinaryData(
  Buffer.from(markdown, 'utf8'),
  filename,
  'text/markdown'
);

return [{
  json: {
    projeto_id: projeto.id,
    filename,
    markdown_preview: markdown.slice(0, 500),
    n_pecas: sociais.length,
    mensagem_log: 'Output Drive: ' + filename + ' (' + sociais.length + ' peças IG)'
  },
  binary: { data: binary }
}];
